const contactForm=document.getElementById('my-contact-form');const successBox=document.getElementById('success-message');const emailRegex=/^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;if(contactForm){const emailInput=document.getElementById('email');const emailConfirm=document.getElementById('email-confirm');const emailError=document.getElementById('email-error');const emailFormatError=document.getElementById('email-format-error');function validateEmail(){const val=emailInput.value;const isValidFormat=emailRegex.test(val);emailFormatError.style.display=(!val||isValidFormat)?'none':'block';const matches=val===emailConfirm.value;emailError.style.display=(emailConfirm.value&&!matches)?'block':'none';return isValidFormat&&matches;}
emailInput.addEventListener('blur',function(){const val=emailInput.value;if(val)emailFormatError.style.display=emailRegex.test(val)?'none':'block';});emailInput.addEventListener('keydown',function(e){if(e.key==='Enter'){const val=emailInput.value;if(val)emailFormatError.style.display=emailRegex.test(val)?'none':'block';}});emailConfirm.addEventListener('blur',function(){if(emailConfirm.value){emailError.style.display=(emailInput.value===emailConfirm.value)?'none':'block';}});emailConfirm.addEventListener('keydown',function(e){if(e.key==='Enter'&&emailConfirm.value){emailError.style.display=(emailInput.value===emailConfirm.value)?'none':'block';}});contactForm.addEventListener('submit',function(e){e.preventDefault();if(!validateEmail()){if(!emailRegex.test(emailInput.value)){emailFormatError.style.display='block';}else{emailError.style.display='block';}
emailConfirm.focus();return;}
const submitBtn=contactForm.querySelector('button[type="submit"]');const originalBtnText=submitBtn.innerHTML;submitBtn.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Wird gesendet...';submitBtn.disabled=true;const formData=new FormData(contactForm);formData.delete('_email_confirm');fetch(contactForm.action,{method:'POST',body:formData,headers:{'Accept':'application/json'}}).then(response=>{if(response.ok){contactForm.style.display='none';successBox.style.display='block';}else{alert("Es gab leider ein Problem beim Senden.");submitBtn.innerHTML=originalBtnText;submitBtn.disabled=false;}}).catch(error=>{alert("Verbindungsfehler.");submitBtn.innerHTML=originalBtnText;submitBtn.disabled=false;});});}
function closeSuccess(){successBox.style.display='none';contactForm.style.display='flex';contactForm.reset();}